root.js-content:
stp.writeLog("Start:Receive Amend Agreement");
stp.setAutoProcess(true);
stp.setUserId("CSBANK");
var sType = stp.getMsgTagVal("FA_BUSI_TYPE");
var iLen= sType.toString().length();
stp.writeLog("iLen**************"+iLen);
if(iLen == 0){
  var sType = stp.getXslMsgTagVal("message/out-msg-content/trx","FA_BUSI_TYPE");
}
stp.writeLog("sType**************"+sType);
var sMainRef = "";
var sUnitCode = "";

   sMainRef = stp.getXslMsgTagVal("message/out-msg-content/trx","FA_CE_MAIN_REF");
   if(sType == "SF" || sType == "DD"){
     sUnitCode = stp.getXslMsgTagVal("message/out-msg-content/trx","FA_BUYER_ID");
   }else{
     sUnitCode = stp.getXslMsgTagVal("message/out-msg-content/trx","FA_SEL_ID");
   }

stp.writeLog("sMainRef**************"+sMainRef);
stp.setCmpId(sUnitCode);
stp.setMainRef(sMainRef);
stp.updateFieldValue("PARENT_MAIN_REF",sMainRef);
stp.updateFieldValue("CURRNT_STATUS","Amended Agreement");
stp.writeLog("End: Receive Amend Agreement");
